function toKelvin(value: number, unit: string) {
  if (unit === "c") return value + 273.15;
  if (unit === "f") return (value - 32) * 5 / 9 + 273.15;
  return value;
}

function fromKelvin(value: number, unit: string) {
  if (unit === "c") return value - 273.15;
  if (unit === "f") return (value - 273.15) * 9 / 5 + 32;
  return value;
}

function convertPressureFromAtm(value: number, unit: string) {
  return value / pressureToAtm[unit];
}

function convertVolumeFromL(value: number, unit: string) {
  return value / volumeToL[unit];
}

function concentrationLabel(unit: string) {
  return ({ m: "M", mm: "mM", um: "uM", percent: "%", ppm: "ppm" } as Record<string, string>)[unit] || unit;
}

