function calculate(kind: Kind, values: Record<string, string>): Result {
  if (kind === "idealGas") {
    const R = 0.082057;
    const pAtm = num(values, "pressure") * pressureToAtm[values.pressureUnit];
    const vL = num(values, "volume") * volumeToL[values.volumeUnit];
    const n = num(values, "moles");
    const tK = toKelvin(num(values, "temperature"), values.temperatureUnit);
    if (values.solveFor === "pressure") {
      const answer = n * R * tK / vL;
      return { label: "Pressure P", value: `${sci(convertPressureFromAtm(answer, values.pressureUnit))} ${values.pressureUnit}`, detail: "Solved from P = nRT / V", step: `P = nRT / V = ${n} x 0.08206 x ${fmt(tK, 2)} / ${fmt(vL, 3)} = ${sci(answer)} atm. R is 0.08206 L atm per mol K.`, cards: [{ label: "R value used", value: "0.08206 L atm/mol K" }, { label: "Temperature", value: `${fmt(tK, 2)} K` }] };
    }
    if (values.solveFor === "volume") {
      const answer = n * R * tK / pAtm;
      return { label: "Volume V", value: `${sci(convertVolumeFromL(answer, values.volumeUnit))} ${values.volumeUnit}`, detail: "Solved from V = nRT / P", step: `V = nRT / P = ${n} x 0.08206 x ${fmt(tK, 2)} / ${fmt(pAtm, 4)} = ${sci(answer)} L.`, cards: [{ label: "Pressure", value: `${sci(pAtm)} atm` }, { label: "Moles", value: `${sci(n)} mol` }] };
    }
    if (values.solveFor === "moles") {
      const answer = pAtm * vL / (R * tK);
      return { label: "Moles n", value: `${sci(answer)} mol`, detail: "Solved from n = PV / RT", step: `n = PV / RT = ${fmt(pAtm, 4)} x ${fmt(vL, 3)} / (0.08206 x ${fmt(tK, 2)}) = ${sci(answer)} mol.`, cards: [{ label: "Pressure", value: `${sci(pAtm)} atm` }, { label: "Volume", value: `${sci(vL)} L` }] };
    }
    const answerK = pAtm * vL / (n * R);
    return { label: "Temperature T", value: `${sci(fromKelvin(answerK, values.temperatureUnit))} ${values.temperatureUnit}`, detail: "Solved from T = PV / nR", step: `T = PV / nR = ${fmt(pAtm, 4)} x ${fmt(vL, 3)} / (${n} x 0.08206) = ${fmt(answerK, 2)} K.`, cards: [{ label: "Kelvin result", value: `${fmt(answerK, 2)} K` }, { label: "R value used", value: "0.08206 L atm/mol K" }] };
  }

  if (kind === "boylesLaw") {
    const p1 = num(values, "p1") * pressureToAtm[values.p1Unit];
    const v1 = num(values, "v1") * volumeToL[values.v1Unit];
    const p2 = num(values, "p2") * pressureToAtm[values.p2Unit];
    const v2 = num(values, "v2") * volumeToL[values.v2Unit];
    if (values.solveFor === "finalPressure") {
      const answer = p1 * v1 / v2;
      return { label: "Final pressure P2", value: `${sci(convertPressureFromAtm(answer, values.p2Unit))} ${values.p2Unit}`, detail: "Temperature and moles stay constant", step: `P2 = P1 x V1 / V2 = ${fmt(p1, 4)} x ${fmt(v1, 3)} / ${fmt(v2, 3)} = ${sci(answer)} atm.`, cards: [{ label: "Initial P x V", value: `${fmt(p1 * v1, 4)} atm L` }, { label: "Relationship", value: "Inverse" }] };
    }
    const answer = p1 * v1 / p2;
    return { label: "Final volume V2", value: `${sci(convertVolumeFromL(answer, values.v2Unit))} ${values.v2Unit}`, detail: "Temperature and moles stay constant", step: `V2 = P1 x V1 / P2 = ${fmt(p1, 4)} x ${fmt(v1, 3)} / ${fmt(p2, 4)} = ${sci(answer)} L.`, cards: [{ label: "Initial P x V", value: `${fmt(p1 * v1, 4)} atm L` }, { label: "Relationship", value: "Inverse" }] };
  }

  if (kind === "charlesLaw") {
    const t1 = toKelvin(num(values, "t1"), values.t1Unit);
    const t2 = toKelvin(num(values, "t2"), values.t2Unit);
    const v1 = num(values, "v1") * volumeToL[values.v1Unit];
    const v2 = num(values, "v2") * volumeToL[values.v2Unit];
    if (values.solveFor === "finalTemperature") {
      const answerK = t1 * v2 / v1;
      return { label: "Final temperature T2", value: `${sci(fromKelvin(answerK, values.t2Unit))} ${values.t2Unit}`, detail: "Temperature is converted through Kelvin", step: `T2 = T1 x V2 / V1 = ${fmt(t1, 2)} x ${fmt(v2, 3)} / ${fmt(v1, 3)} = ${fmt(answerK, 2)} K.`, cards: [{ label: "Kelvin result", value: `${fmt(answerK, 2)} K` }, { label: "Relationship", value: "Direct" }] };
    }
    const answer = v1 * t2 / t1;
    return { label: "Final volume V2", value: `${sci(convertVolumeFromL(answer, values.v2Unit))} ${values.v2Unit}`, detail: "Temperature is converted through Kelvin", step: `V2 = V1 x T2 / T1 = ${fmt(v1, 3)} x ${fmt(t2, 2)} / ${fmt(t1, 2)} = ${sci(answer)} L.`, cards: [{ label: "Initial temperature", value: `${fmt(t1, 2)} K` }, { label: "Final temperature", value: `${fmt(t2, 2)} K` }] };
  }

  if (kind === "dilution") {
    const c1M = num(values, "c1") * concentrationToM[values.c1Unit];
    const c2M = num(values, "c2") * concentrationToM[values.c2Unit];
    const v1L = num(values, "v1") * volumeToL[values.v1Unit];
    const v2L = num(values, "v2") * volumeToL[values.v2Unit];
    if (values.solveFor === "finalVolume") {
      const answerL = c1M * v1L / c2M;
      const solventL = answerL - v1L;
      return { label: "Final volume V2", value: `${sci(convertVolumeFromL(answerL, values.v2Unit))} ${values.v2Unit}`, detail: `Add ${sci(convertVolumeFromL(solventL, values.v2Unit))} ${values.v2Unit} solvent`, step: `V2 = C1 x V1 / C2 = ${sci(c1M)} x ${sci(v1L)} / ${sci(c2M)} = ${sci(answerL)} L. Solvent to add = V2 - V1.`, cards: [{ label: "Dilution factor", value: fmt(answerL / v1L, 2) }, { label: "Final concentration", value: `${values.c2} ${concentrationLabel(values.c2Unit)}` }] };
    }
    const answerM = c1M * v1L / v2L;
    return { label: "Final concentration C2", value: `${sci(answerM / concentrationToM[values.c2Unit])} ${concentrationLabel(values.c2Unit)}`, detail: "Solute amount stays constant", step: `C2 = C1 x V1 / V2 = ${sci(c1M)} x ${sci(v1L)} / ${sci(v2L)} = ${sci(answerM)} M.`, cards: [{ label: "Dilution factor", value: fmt(v2L / v1L, 2) }, { label: "Solvent added", value: `${sci(convertVolumeFromL(v2L - v1L, values.v2Unit))} ${values.v2Unit}` }] };
  }

  const pka = num(values, "pka");
  if (values.solveFor === "ratio") {
    const ratio = 10 ** (num(values, "targetPh") - pka);
    return { label: "Base / acid ratio", value: `${sci(ratio)} : 1`, detail: "Target pH preparation ratio", step: `[A-]/[HA] = 10^(pH - pKa) = 10^(${values.targetPh} - ${pka}) = ${sci(ratio)}.`, cards: [{ label: "Target pH", value: values.targetPh }, { label: "pKa", value: values.pka }] };
  }
  const ratio = num(values, "base") / num(values, "acid");
  const ph = pka + Math.log10(ratio);
  return { label: "Buffer pH", value: fmt(ph, 3), detail: "Henderson-Hasselbalch result", step: `pH = pKa + log([A-]/[HA]) = ${pka} + log(${values.base}/${values.acid}) = ${fmt(ph, 3)}.`, cards: [{ label: "Base / acid ratio", value: sci(ratio) }, { label: "Useful pH range", value: `${fmt(pka - 1, 2)} to ${fmt(pka + 1, 2)}` }] };
}

function ChemistryTable({ table }: { table: PageConfig["table"] }) {
  return (
    <section className="bg-card border border-border rounded-2xl p-6 shadow-sm mb-8">
      <h2 className="text-2xl font-bold text-foreground mb-4">{table.title}</h2>
      <div className="overflow-x-auto rounded-xl border border-border">
        <table className="w-full text-sm">
          <thead><tr className="bg-muted/80">{table.headers.map((header) => <th key={header} className="text-left font-bold text-foreground px-4 py-3 whitespace-nowrap">{header}</th>)}</tr></thead>
          <tbody>{table.rows.map((row, index) => <tr key={`${row[0]}-${index}`} className={index % 2 === 0 ? "bg-background" : "bg-muted/35"}>{row.map((cell, cellIndex) => <td key={`${cell}-${cellIndex}`} className="px-4 py-3 text-muted-foreground whitespace-nowrap">{cell}</td>)}</tr>)}</tbody>
        </table>
      </div>
    </section>
  );
}

function LinkList({ title, items }: { title: string; items: Array<string | { label: string; href: string }> }) {
  return (
    <section className="bg-card border border-border rounded-2xl p-6 shadow-sm mb-8">
      <h2 className="text-2xl font-bold text-foreground mb-4">{title}</h2>
      <div className="flex flex-wrap gap-2">
        {items.map((item) => {
          const label = typeof item === "string" ? item : item.label;
          const href = typeof item === "string" ? undefined : item.href;
          const className = "rounded-full border border-border bg-muted/50 px-3 py-1.5 text-sm font-semibold text-muted-foreground hover:text-primary transition-colors";
          return href ? <a key={label} href={href} className={className}>{label}</a> : <span key={label} className={className}>{label}</span>;
        })}
      </div>
    </section>
  );
}

export function createAdvancedChemistryCalculatorPage(kind: Kind) {
  const config = CONFIGS[kind];
  function ChemistryCalculatorPage() {
    const guide = getChemistryGuide(config.path);
    const faqs = guide?.faqs ?? config.faqs;
    const [values, setValues] = useState<Record<string, string>>(config.defaults);
    const result = useMemo(() => calculate(kind, values), [values]);
    const setValue = (key: string, value: string) => setValues((current) => ({ ...current, [key]: value }));

    return (
      <>
        <SEOHead title={guide?.title ?? config.title} description={guide?.description ?? config.description} canonical={config.path} keywords={guide?.keywords ?? config.keywords} category="Chemistry" breadcrumbName={guide?.h1 ?? config.h1} schemaType="WebApplication" schemaApplicationCategory="UtilitiesApplication" faqs={faqs} />
        <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
          <div className="mb-8">
            <span className="text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/50 px-3 py-1 rounded-full mb-4 inline-block">Chemistry</span>
            <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">{guide?.h1 ?? config.h1}</h1>
            <p className="text-muted-foreground leading-relaxed">{guide?.description ?? config.description}</p>
          </div>
          <AdPlaceholder size="banner" className="mb-8" />
          <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
              {config.fields.map((field) => (
                <div key={field.key}>
                  <label htmlFor={`${kind}-${field.key}`} className="text-sm font-semibold text-foreground block mb-2">{field.label}</label>
                  {field.type === "select" ? (
                    <select id={`${kind}-${field.key}`} value={values[field.key]} onChange={(event) => setValue(field.key, event.target.value)} className={inputClass}>{field.options?.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}</select>
                  ) : (
                    <div className={field.unit ? "grid grid-cols-[1fr_auto] gap-2" : ""}>
                      <input id={`${kind}-${field.key}`} type="number" inputMode="decimal" value={values[field.key] ?? ""} onChange={(event) => setValue(field.key, event.target.value)} className={inputClass} />
                      {field.unit && <span className="px-3 py-2 rounded-xl border border-border bg-muted/50 text-sm font-bold text-muted-foreground flex items-center">{field.unit}</span>}
                    </div>
                  )}
                  {field.hint && <p className="text-xs text-muted-foreground mt-1">{field.hint}</p>}
                </div>
              ))}
            </div>
            <motion.div key={Object.values(values).join("-")} initial={{ opacity: 0.75, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.22 }}>
              <div className="bg-gradient-to-br from-emerald-500 to-cyan-700 rounded-2xl p-6 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/75 mb-1">{result.label}</p>
                <p className="text-4xl sm:text-5xl font-black text-white tracking-tight break-words" data-testid={`result-${kind}`}>{result.value}</p>
                <p className="text-sm text-white/80 mt-2">{result.detail}</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4">{result.cards.map((card) => <div key={card.label} className="bg-accent/50 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">{card.label}</p><p className="text-lg font-black text-foreground">{card.value}</p></div>)}</div>
              <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4">
                <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p>
                <p className="text-sm text-foreground" data-testid={`result-steps-${kind}`}>{result.step}</p>
                {result.extra && <ul className="mt-3 space-y-1 text-sm text-muted-foreground">{result.extra.map((line) => <li key={line}>{line}</li>)}</ul>}
              </div>
            </motion.div>
          </section>
          <ShareButton />
          <ChemistryTable table={config.table} />
          {guide ? <ChemistryExpandedContent guide={guide} /> : <section className="mb-8 space-y-6">{config.h2s.map((section) => <div key={section.title}><h2 className="text-2xl font-bold text-foreground mb-2">{section.title}</h2><p className="text-muted-foreground leading-relaxed">{section.body}</p></div>)}</section>}
          <ScienceRelatedCalculatorCards title="Related Calculators" items={config.related} fallbackCategory="Chemistry" />
          <section className="mb-8"><h2 className="text-2xl font-bold text-foreground mb-4">{guide?.faqHeading ?? "Frequently Asked Questions"}</h2><div className="space-y-3">{faqs.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
          <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        </main>
      </>
    );
  }
  return ChemistryCalculatorPage;
}
